changeSet.sql:
DO $$ BEGIN CREATE TEMP TABLE _slcn7_dup_map ON COMMIT DROP AS SELECT t.tenant_id, t.id AS dup_id, m.keep_id FROM nexus.topics t JOIN ( SELECT tenant_id, collection, label, MIN(id) AS keep_id FROM nexus.topics WHERE parent_id IS NULL GROUP BY tenant_id, collection, label HAVING COUNT(*) > 1 ) m ON m.tenant_id = t.tenant_id AND m.collection = t.collection AND m.label = t.label WHERE t.parent_id IS NULL AND t.id <> m.keep_id;
-- Move assignments onto the kept topic (skip docs already there), then drop -- the redundant rows. Both statements fire the doc_count trigger. INSERT INTO nexus.topic_assignments (tenant_id, doc_id, topic_id, assigned_by, similarity, assigned_at, source_collection) SELECT ta.tenant_id, ta.doc_id, dm.keep_id, ta.assigned_by, ta.similarity, ta.assigned_at, ta.source_collection FROM nexus.topic_assignments ta JOIN _slcn7_dup_map dm ON dm.dup_id = ta.topic_id AND dm.tenant_id = ta.tenant_id ON CONFLICT (tenant_id, doc_id, topic_id) DO NOTHING;
DELETE FROM nexus.topic_assignments ta USING _slcn7_dup_map dm WHERE dm.dup_id = ta.topic_id AND dm.tenant_id = ta.tenant_id;
-- Re-parent any children of a dup onto the kept topic. UPDATE nexus.topics t SET parent_id = dm.keep_id FROM _slcn7_dup_map dm WHERE t.parent_id = dm.dup_id AND t.tenant_id = dm.tenant_id;
-- Drop links touching a dup (recomputable co-occurrence edges). DELETE FROM nexus.topic_links tl USING _slcn7_dup_map dm WHERE (tl.from_topic_id = dm.dup_id OR tl.to_topic_id = dm.dup_id) AND tl.tenant_id = dm.tenant_id;
-- Finally drop the redundant root topics. DELETE FROM nexus.topics t USING _slcn7_dup_map dm WHERE t.id = dm.dup_id AND t.tenant_id = dm.tenant_id; END $$;

CREATE UNIQUE INDEX IF NOT EXISTS idx_topics_root_tenant_collection_label
    ON nexus.topics (tenant_id, collection, label)
 WHERE parent_id IS NULL;
